import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import CommunitySetup from '../../components/CommunitySetup';

export default function CommunityAdminDashboard() {
  const { user } = useAuth();
  const [community, setCommunity] = useState(null);
  const [noCommunity, setNoCommunity] = useState(false);
  const [events, setEvents] = useState([]);
  const [joinRequests, setJoinRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');

  const fetchData = async () => {
    setLoading(true);
    try {
      const communityRes = await api.get('/communities/my/profile');
      const c = communityRes.data.data;
      setCommunity(c);
      setNoCommunity(false);

      const [eventsRes, requestsRes] = await Promise.all([
        api.get('/events/my-community'),
        api.get(`/communities/${c._id}/join-requests`),
      ]);
      setEvents(eventsRes.data.data || []);
      setJoinRequests(requestsRes.data.data || []);
    } catch (err) {
      if (err.response?.status === 404) {
        setNoCommunity(true);
      } else {
        toast.error('Failed to load dashboard');
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleJoinRequest = async (communityId, requestId, action, userName) => {
    const endpoint = `/communities/${communityId}/join-requests/${requestId}/${action}`;
    try {
      await api.put(endpoint, action === 'reject' ? { reason: prompt('Reason (optional):') || '' } : {});
      toast.success(`Request ${action}ed for ${userName}`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed');
    }
  };

  if (loading) return (
    <div className="loading-screen" style={{
      minHeight: '400px',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '16px'
    }}>
      <div className="spinner" style={{ width: '40px', height: '40px', borderWidth: '3px' }} />
      <span style={{ color: 'var(--text-secondary)' }}>Loading community dashboard...</span>
    </div>
  );

  if (noCommunity) {
    return <CommunitySetup onSetupComplete={(c) => { setCommunity(c); setNoCommunity(false); }} />;
  }

  const getCategoryIcon = () => {
    const icons = {
      Technology: '💻',
      Arts: '🎨',
      Sports: '⚽',
      Academic: '📚',
      Cultural: '🎭',
      Business: '💼',
      Science: '🔬',
      Social: '🤝',
      Other: '🌟'
    };
    return icons[community?.category] || '🏛️';
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'approved': return '#10b981';
      case 'pending': return 'var(--warning)';
      case 'rejected': return '#ef4444';
      default: return 'var(--text-muted)';
    }
  };

  return (
    <div className="page-wrapper" style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: 1200, margin: '0 auto', padding: '32px 20px' }}>

        {/* Enhanced Header */}
        <div className="page-header" style={{ marginBottom: 32 }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'flex-start',
            flexWrap: 'wrap',
            gap: '16px'
          }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                <div style={{ 
                  width: '48px', 
                  height: '48px', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '24px'
                }}>
                  🏛️
                </div>
                <div>
                  <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                    COMMUNITY <span className="gradient-text">DASHBOARD</span>
                  </h2>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '4px' }}>
                    {community?.name} — Manage your community effectively
                  </p>
                </div>
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <Link to="/community-admin/events" className="btn btn-primary" style={{ 
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span>📅</span> Manage Events
              </Link>
              <Link to="/community-admin/members" className="btn btn-outline" style={{ 
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span>👥</span> View Members
              </Link>
            </div>
          </div>
        </div>

        {/* Enhanced Stats Grid */}
        {community && (
          <div className="grid grid-4" style={{ marginBottom: 40, gap: '20px' }}>
            {[
              { label: 'Total Members', value: community.members?.length || 0, icon: '👥', color: 'var(--purple-light)', trend: '+12%', bgGradient: 'linear-gradient(135deg, rgba(139, 92, 246, 0.1), rgba(139, 92, 246, 0.05))' },
              { label: 'Pending Requests', value: joinRequests.length, icon: '⏳', color: 'var(--warning)', trend: `${joinRequests.length} waiting`, bgGradient: 'linear-gradient(135deg, rgba(245, 158, 11, 0.1), rgba(245, 158, 11, 0.05))' },
              { label: 'Total Events', value: events.length, icon: '📅', color: 'var(--cyan-accent)', trend: 'All time', bgGradient: 'linear-gradient(135deg, rgba(6, 182, 212, 0.1), rgba(6, 182, 212, 0.05))' },
              { label: 'Published Events', value: events.filter(e => e.status === 'published').length, icon: '🚀', color: '#10b981', trend: 'Active', bgGradient: 'linear-gradient(135deg, rgba(16, 185, 129, 0.1), rgba(16, 185, 129, 0.05))' },
            ].map((s, i) => (
              <div key={i} className="stat-card" style={{ 
                background: s.bgGradient,
                border: '1px solid rgba(255,255,255,0.1)',
                transition: 'transform 0.2s, box-shadow 0.2s',
                cursor: 'pointer',
                position: 'relative',
                overflow: 'hidden'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
                  <span style={{ fontSize: '2rem' }}>{s.icon}</span>
                  <span style={{ 
                    fontSize: '0.75rem', 
                    color: s.color,
                    background: 'rgba(255,255,255,0.1)',
                    padding: '4px 8px',
                    borderRadius: 'var(--radius-sm)'
                  }}>{s.trend}</span>
                </div>
                <div className="stat-value" style={{ color: s.color, fontSize: '2.5rem', fontWeight: 'bold' }}>{s.value}</div>
                <div className="stat-label" style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '8px' }}>{s.label}</div>
              </div>
            ))}
          </div>
        )}

        {/* Tabs for better organization */}
        <div style={{ 
          borderBottom: '1px solid rgba(255,255,255,0.1)',
          marginBottom: '32px',
          display: 'flex',
          gap: '32px'
        }}>
          {[
            { id: 'overview', label: 'Overview', icon: '📊' },
            { id: 'requests', label: `Join Requests ${joinRequests.length > 0 ? `(${joinRequests.length})` : ''}`, icon: '👋' },
            { id: 'events', label: 'Events', icon: '📅' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              style={{
                padding: '12px 0',
                background: 'none',
                border: 'none',
                color: activeTab === tab.id ? 'var(--purple-light)' : 'var(--text-muted)',
                cursor: 'pointer',
                fontSize: '0.9rem',
                fontWeight: activeTab === tab.id ? '600' : '400',
                borderBottom: activeTab === tab.id ? `2px solid var(--purple-light)` : '2px solid transparent',
                transition: 'all 0.2s',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}
            >
              <span>{tab.icon}</span> {tab.label}
            </button>
          ))}
        </div>

        {/* Tab Content */}
        {activeTab === 'overview' && (
          <>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '28px', marginBottom: '40px' }}>
              {/* Enhanced Pending Join Requests */}
              <div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                  <div>
                    <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', margin: 0, display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <span>👋</span> Recent Join Requests
                      {joinRequests.length > 0 && (
                        <span style={{ 
                          background: 'var(--warning)', 
                          color: 'black', 
                          borderRadius: '100px', 
                          padding: '2px 10px', 
                          fontSize: '0.7rem',
                          fontWeight: 'bold'
                        }}>
                          {joinRequests.length} pending
                        </span>
                      )}
                    </h3>
                    <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: '4px' }}>
                      Review and manage membership requests
                    </p>
                  </div>
                  <Link to="/community-admin/members" style={{ 
                    fontSize: '0.8rem', 
                    color: 'var(--purple-light)',
                    textDecoration: 'none',
                    fontWeight: '500'
                  }}>View All →</Link>
                </div>

                {joinRequests.length === 0 ? (
                  <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
                    <div style={{ fontSize: '3rem', marginBottom: '16px' }}>✅</div>
                    <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>No pending requests</div>
                    <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '8px' }}>All join requests have been processed</div>
                  </div>
                ) : (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    {joinRequests.slice(0, 5).map(req => (
                      <div key={req._id} className="card" style={{ padding: '16px', transition: 'transform 0.2s' }}>
                        <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px', marginBottom: '12px' }}>
                          <div className="avatar" style={{ 
                            width: '40px', 
                            height: '40px', 
                            background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontWeight: 'bold'
                          }}>{req.user?.name?.charAt(0)}</div>
                          <div style={{ flex: 1 }}>
                            <div style={{ fontWeight: 600, fontSize: '0.9rem', marginBottom: '2px' }}>{req.user?.name}</div>
                            <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>{req.user?.itNumber}</div>
                          </div>
                          <span style={{ 
                            fontSize: '0.7rem', 
                            color: 'var(--warning)',
                            background: 'rgba(245, 158, 11, 0.1)',
                            padding: '2px 8px',
                            borderRadius: 'var(--radius-sm)'
                          }}>Pending</span>
                        </div>
                        {req.message && (
                          <p style={{ 
                            fontSize: '0.8rem', 
                            color: 'var(--text-secondary)', 
                            marginBottom: '12px', 
                            fontStyle: 'italic',
                            padding: '8px',
                            background: 'var(--bg-elevated)',
                            borderRadius: 'var(--radius-sm)',
                            borderLeft: `3px solid var(--purple-light)`
                          }}>
                            "{req.message}"
                          </p>
                        )}
                        <div style={{ display: 'flex', gap: '8px' }}>
                          <button 
                            onClick={() => handleJoinRequest(community._id, req._id, 'approve', req.user?.name)} 
                            className="btn btn-success btn-sm" 
                            style={{ 
                              flex: 1, 
                              justifyContent: 'center',
                              background: 'linear-gradient(135deg, #10b981, #059669)',
                              border: 'none'
                            }}
                          >
                            ✓ Approve
                          </button>
                          <button 
                            onClick={() => handleJoinRequest(community._id, req._id, 'reject', req.user?.name)} 
                            className="btn btn-danger btn-sm" 
                            style={{ 
                              flex: 1, 
                              justifyContent: 'center',
                              background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                              border: 'none'
                            }}
                          >
                            ✗ Reject
                          </button>
                        </div>
                      </div>
                    ))}
                    {joinRequests.length > 5 && (
                      <Link to="/community-admin/members" style={{ 
                        textAlign: 'center', 
                        fontSize: '0.85rem', 
                        color: 'var(--purple-light)', 
                        padding: '12px',
                        textDecoration: 'none',
                        fontWeight: '500'
                      }}>
                        +{joinRequests.length - 5} more requests →
                      </Link>
                    )}
                  </div>
                )}
              </div>

              {/* Enhanced Recent Events */}
              <div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                  <div>
                    <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', margin: 0, display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <span>📅</span> Recent Events
                    </h3>
                    <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: '4px' }}>
                      Your upcoming and recent community events
                    </p>
                  </div>
                  <Link to="/community-admin/events" style={{ 
                    fontSize: '0.8rem', 
                    color: 'var(--purple-light)',
                    textDecoration: 'none',
                    fontWeight: '500'
                  }}>All Events →</Link>
                </div>

                {events.length === 0 ? (
                  <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
                    <div style={{ fontSize: '3rem', marginBottom: '16px' }}>📅</div>
                    <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', marginBottom: '8px' }}>No events yet</div>
                    <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginBottom: '16px' }}>Create your first community event</div>
                    <Link to="/community-admin/events" className="btn btn-primary btn-sm" style={{ 
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '8px'
                    }}>
                      <span>➕</span> Create Event
                    </Link>
                  </div>
                ) : (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    {events.slice(0, 5).map(ev => (
                      <div key={ev._id} className="card" style={{ padding: '16px', transition: 'transform 0.2s' }}>
                        <div className="flex-between" style={{ marginBottom: '8px' }}>
                          <div style={{ fontWeight: 600, fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <span>🎉</span> {ev.title}
                          </div>
                          <span className={`badge badge-${ev.status}`} style={{ 
                            background: ev.status === 'published' ? 'linear-gradient(135deg, #10b981, #059669)' :
                                       ev.status === 'draft' ? 'linear-gradient(135deg, var(--warning), #f59e0b)' : 
                                       'linear-gradient(135deg, #6b7280, #4b5563)'
                          }}>
                            {ev.status === 'published' ? '✓ Published' : ev.status === 'draft' ? '📝 Draft' : '⏸️ Cancelled'}
                          </span>
                        </div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
                          <span>📅 {new Date(ev.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</span>
                          <span>👥 {ev.participants?.length || 0} registered</span>
                          {ev.location && <span>📍 {ev.location}</span>}
                        </div>
                        {ev.status === 'published' && ev.participants?.length > 0 && (
                          <div style={{ marginTop: '8px' }}>
                            <div style={{ 
                              height: '4px', 
                              background: 'var(--bg-elevated)', 
                              borderRadius: '2px',
                              overflow: 'hidden'
                            }}>
                              <div style={{ 
                                width: `${(ev.participants?.length / (community.members?.length || 1)) * 100}%`, 
                                height: '100%', 
                                background: 'linear-gradient(90deg, var(--purple-primary), var(--cyan-accent))'
                              }} />
                            </div>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </>
        )}

        {activeTab === 'requests' && (
          <div>
            <div style={{ marginBottom: '24px' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', marginBottom: '8px' }}>
                All Join Requests
              </h3>
              <p style={{ color: 'var(--text-muted)' }}>Review and manage all membership requests</p>
            </div>
            {joinRequests.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: '16px' }}>✅</div>
                <div style={{ fontSize: '1.1rem', marginBottom: '8px' }}>No pending requests</div>
                <div style={{ color: 'var(--text-muted)' }}>All membership requests have been processed</div>
              </div>
            ) : (
              <div style={{ display: 'grid', gap: '16px' }}>
                {joinRequests.map(req => (
                  <div key={req._id} className="card" style={{ padding: '20px' }}>
                    {/* Request details - similar to above but with all items */}
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px' }}>
                      <div className="avatar" style={{ 
                        width: '48px', 
                        height: '48px', 
                        background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                        fontSize: '1.2rem'
                      }}>{req.user?.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '1rem', marginBottom: '4px' }}>{req.user?.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '8px' }}>{req.user?.email} • {req.user?.itNumber}</div>
                        {req.message && (
                          <p style={{ 
                            fontSize: '0.85rem', 
                            color: 'var(--text-secondary)', 
                            marginBottom: '16px',
                            padding: '12px',
                            background: 'var(--bg-elevated)',
                            borderRadius: 'var(--radius-sm)',
                            borderLeft: `3px solid var(--purple-light)`
                          }}>
                            "{req.message}"
                          </p>
                        )}
                        <div style={{ display: 'flex', gap: '12px' }}>
                          <button onClick={() => handleJoinRequest(community._id, req._id, 'approve', req.user?.name)} className="btn btn-success">✓ Approve</button>
                          <button onClick={() => handleJoinRequest(community._id, req._id, 'reject', req.user?.name)} className="btn btn-danger">✗ Reject</button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === 'events' && (
          <div>
            <div style={{ marginBottom: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', marginBottom: '8px' }}>
                  Community Events
                </h3>
                <p style={{ color: 'var(--text-muted)' }}>Manage and organize events for your community</p>
              </div>
              <Link to="/community-admin/events/new" className="btn btn-primary">
                + Create New Event
              </Link>
            </div>
            {events.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: '16px' }}>📅</div>
                <div style={{ fontSize: '1.1rem', marginBottom: '8px' }}>No events yet</div>
                <div style={{ color: 'var(--text-muted)', marginBottom: '24px' }}>Start by creating your first community event</div>
                <Link to="/community-admin/events/new" className="btn btn-primary">Create Event →</Link>
              </div>
            ) : (
              <div style={{ display: 'grid', gap: '16px' }}>
                {events.map(ev => (
                  <div key={ev._id} className="card" style={{ padding: '20px' }}>
                    <div className="flex-between" style={{ marginBottom: '12px' }}>
                      <div>
                        <div style={{ fontWeight: 600, fontSize: '1.1rem', marginBottom: '4px' }}>{ev.title}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                          {new Date(ev.startDate).toLocaleDateString()} • {ev.participants?.length || 0} participants
                        </div>
                      </div>
                      <span className={`badge badge-${ev.status}`} style={{ 
                        background: ev.status === 'published' ? 'linear-gradient(135deg, #10b981, #059669)' :
                                   ev.status === 'draft' ? 'linear-gradient(135deg, var(--warning), #f59e0b)' : 
                                   'linear-gradient(135deg, #6b7280, #4b5563)'
                      }}>
                        {ev.status}
                      </span>
                    </div>
                    {ev.description && (
                      <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', marginBottom: '16px' }}>
                        {ev.description.substring(0, 150)}...
                      </p>
                    )}
                    <div style={{ display: 'flex', gap: '12px' }}>
                      <Link to={`/community-admin/events/${ev._id}`} className="btn btn-outline btn-sm">View Details</Link>
                      <Link to={`/community-admin/events/${ev._id}/edit`} className="btn btn-primary btn-sm">Edit</Link>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Enhanced Community Card */}
        {community && (
          <div style={{ marginTop: 48 }}>
            <div style={{ marginBottom: '20px' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', margin: 0, display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span>🏛️</span> YOUR COMMUNITY
              </h3>
              <p style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: '4px' }}>
                Community overview and settings
              </p>
            </div>

            <div className="card" style={{ 
              padding: '24px',
              background: 'linear-gradient(135deg, var(--bg-secondary), var(--bg-elevated))',
              border: '1px solid rgba(255,255,255,0.05)'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '24px', flexWrap: 'wrap' }}>
                <div className="avatar avatar-xl" style={{ 
                  borderRadius: 'var(--radius-lg)', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                  width: '80px',
                  height: '80px',
                  fontSize: '2rem',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}>
                  {community.name?.charAt(0)}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flexWrap: 'wrap', marginBottom: '12px' }}>
                    <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', margin: 0 }}>
                      {community.name}
                    </h3>
                    <span className={`badge badge-${community.status}`} style={{ 
                      background: `linear-gradient(135deg, ${getStatusColor(community.status)}, ${getStatusColor(community.status)}cc)`,
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px'
                    }}>
                      {community.status === 'approved' ? '✓' : community.status === 'pending' ? '⏳' : '✗'} {community.status}
                    </span>
                    <span className={`badge badge-${community.category?.toLowerCase()}`} style={{ 
                      background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px'
                    }}>
                      {getCategoryIcon()} {community.category}
                    </span>
                  </div>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginBottom: '16px', lineHeight: '1.5' }}>
                    {community.description}
                  </p>
                  <div style={{ display: 'flex', gap: '24px', flexWrap: 'wrap', fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <span>👥</span> {community.members?.length || 0} Members
                    </span>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <span>📅</span> {events.length} Events
                    </span>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                      <span>🎂</span> Since {new Date(community.createdAt).toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                    </span>
                  </div>
                </div>
                <Link to="/community-admin/profile" className="btn btn-outline" style={{ 
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span>✏️</span> Edit Profile
                </Link>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
